import{_ as a,c as e,a0 as s,o as d}from"./chunks/framework.B6JXc2q-.js";const h=JSON.parse('{"title":"系统总览（System Overview）","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/system_overview.md","filePath":"architecture/system_overview.md"}'),n={name:"architecture/system_overview.md"};function c(o,t,r,i,p,l){return d(),e("div",null,t[0]||(t[0]=[s(`<h1 id="系统总览-system-overview" tabindex="-1">系统总览（System Overview） <a class="header-anchor" href="#系统总览-system-overview" aria-label="Permalink to &quot;系统总览（System Overview）&quot;">​</a></h1><p>版本：v1.0 状态：正式架构文档 最后更新：2026-03-28</p><p>本文档是 xiaomusic-core 文档体系的总纲，定义系统一级边界、各模块职责与文档优先级关系。</p><hr><h2 id="_1-系统一级边界" tabindex="-1">1. 系统一级边界 <a class="header-anchor" href="#_1-系统一级边界" aria-label="Permalink to &quot;1. 系统一级边界&quot;">​</a></h2><p>系统由以下九个一级边界组成。每个边界有且只有一个核心职责，跨边界调用必须通过明确的接口层。</p><table tabindex="0"><thead><tr><th>边界</th><th>核心职责</th><th>代码入口</th></tr></thead><tbody><tr><td><strong>api</strong></td><td>对外 HTTP 接口层，承载 v1 Public API 与 Internal API</td><td><code>xiaomusic/api/</code></td></tr><tr><td><strong>runtime</strong></td><td>系统主协调对象，管理各子系统生命周期与依赖注入</td><td><code>xiaomusic/xiaomusic.py</code></td></tr><tr><td><strong>playback</strong></td><td>播放编排层，负责策略决策、队列管理与状态快照输出</td><td><code>xiaomusic/playback/</code>、<code>xiaomusic/core/</code></td></tr><tr><td><strong>source</strong></td><td>媒体来源解析，提供可播放流 URL 与曲目事实</td><td><code>xiaomusic/adapters/sources/</code>、<code>xiaomusic/core/source/</code></td></tr><tr><td><strong>device</strong></td><td>设备抽象与设备侧命令执行</td><td><code>xiaomusic/device_manager.py</code>、<code>xiaomusic/device_player.py</code>、<code>xiaomusic/core/device/</code></td></tr><tr><td><strong>auth</strong></td><td>小米账号认证状态管理与会话维护</td><td><code>xiaomusic/auth.py</code>、<code>xiaomusic/security/token_store.py</code></td></tr><tr><td><strong>config</strong></td><td>运行时配置对象管理与持久化</td><td><code>xiaomusic/config.py</code>、<code>xiaomusic/config_manager.py</code></td></tr><tr><td><strong>relay</strong></td><td>站内流媒体中转，建立 relay session 并输出 <code>/relay/stream/{sid}</code> 端点</td><td><code>xiaomusic/relay/</code></td></tr><tr><td><strong>webui</strong></td><td>前端展示层，通过 Public API 与 Internal API 消费后端状态</td><td><code>xiaomusic/webui/</code></td></tr></tbody></table><hr><h2 id="_2-边界调用规则" tabindex="-1">2. 边界调用规则 <a class="header-anchor" href="#_2-边界调用规则" aria-label="Permalink to &quot;2. 边界调用规则&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>webui</span></span>
<span class="line"><span>  → Public API (/api/v1/*)        ← 所有外部调用方</span></span>
<span class="line"><span>  → Internal API (/api/auth/*, /api/file/*)  ← 仅 WebUI</span></span>
<span class="line"><span></span></span>
<span class="line"><span>api</span></span>
<span class="line"><span>  → playback（通过 facade）</span></span>
<span class="line"><span>  → runtime（通过 runtime_provider）</span></span>
<span class="line"><span>  → relay（只读查询）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>playback</span></span>
<span class="line"><span>  → source（解析媒体）</span></span>
<span class="line"><span>  → device（下发命令）</span></span>
<span class="line"><span>  → relay（准备投递流）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>runtime</span></span>
<span class="line"><span>  → auth</span></span>
<span class="line"><span>  → config</span></span>
<span class="line"><span>  → device</span></span>
<span class="line"><span>  → 音乐库（music_library）</span></span>
<span class="line"><span>  → 事件总线（event_bus）</span></span></code></pre></div><p><strong>严格禁止的跨边界调用：</strong></p><ul><li><code>source</code> 不得直接调用 <code>device</code></li><li><code>webui</code> 不得依赖 <code>playback</code> / <code>runtime</code> 内部对象</li><li><code>api</code> 层不得直接读取设备底层状态绕过 <code>playback</code> 快照构建器</li><li><code>relay</code> 不得主动触发播放命令（只提供流服务）</li></ul><hr><h2 id="_3-各边界当前状态" tabindex="-1">3. 各边界当前状态 <a class="header-anchor" href="#_3-各边界当前状态" aria-label="Permalink to &quot;3. 各边界当前状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>边界</th><th>边界稳定性</th><th>说明</th></tr></thead><tbody><tr><td>api</td><td>稳定</td><td>v1 白名单接口已形成正式契约，<code>api_v1_spec.md</code> 为权威</td></tr><tr><td>playback</td><td>稳定</td><td>状态快照、revision、SSE 推送已实现；<code>facade.py</code> 是唯一入口</td></tr><tr><td>source</td><td>稳定</td><td>四种来源已形成统一接口，<code>SourcePlugin.resolve()</code> 是唯一规范点</td></tr><tr><td>device</td><td>稳定</td><td>设备执行层边界清晰，transport（mina/miio）已抽象</td></tr><tr><td>auth</td><td>稳定</td><td>两层认证状态模型已明确，<code>auth.json</code> 是事实来源</td></tr><tr><td>config</td><td>稳定</td><td><code>Config</code> 对象是运行时单一配置入口</td></tr><tr><td>relay</td><td>稳定</td><td>relay/proxy 语义已收口，<code>network_audio</code> 废弃术语已清除</td></tr><tr><td>runtime</td><td>过渡</td><td><code>XiaoMusic</code> 类仍承担部分协调职责，逐步向 playback/facade 下沉；一级边界定义不变</td></tr><tr><td>webui</td><td>过渡</td><td>前端已切换至 SSE 主通道 + <code>serverState</code> 消费模型；旧推测型逻辑已清除</td></tr></tbody></table><p>&quot;过渡&quot;表示内部实现仍在收敛，但一级边界定义和对外接口契约不因此改变。</p><hr><h2 id="_4-文档优先级关系" tabindex="-1">4. 文档优先级关系 <a class="header-anchor" href="#_4-文档优先级关系" aria-label="Permalink to &quot;4. 文档优先级关系&quot;">​</a></h2><p>当多份文档对同一事项有描述时，以下优先级从高到低生效：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. docs/api/api_v1_spec.md</span></span>
<span class="line"><span>   ↳ v1 接口行为、字段、错误模型的最终权威</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. docs/spec/*</span></span>
<span class="line"><span>   ↳ 状态语义、SSE 协议、WebUI 状态机、auth 恢复等运行时行为规范</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. docs/architecture/*（含本文档）</span></span>
<span class="line"><span>   ↳ 系统结构、层级边界、模块归属决策</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. docs/development/*</span></span>
<span class="line"><span>   ↳ 开发流程、改动前置规则、文档更新约束</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. ARCHITECTURE.md</span></span>
<span class="line"><span>   ↳ 接口分层与调用关系的高层概述（与本文档互补，无冲突时均有效）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. docs/dev/*（归档）</span></span>
<span class="line"><span>   ↳ 历史实施计划与验收报告，不作为当前实现依据</span></span></code></pre></div><hr><h2 id="_5-新功能归属判断" tabindex="-1">5. 新功能归属判断 <a class="header-anchor" href="#_5-新功能归属判断" aria-label="Permalink to &quot;5. 新功能归属判断&quot;">​</a></h2><p>新功能落地前，必须先判断归属边界：</p><ul><li><strong>涉及对外接口</strong>：归 <code>api</code>，同步修改 <code>api_v1_spec.md</code></li><li><strong>涉及媒体来源解析</strong>：归 <code>source</code>，实现 <code>SourcePlugin.resolve()</code></li><li><strong>涉及播放编排与状态</strong>：归 <code>playback</code>，通过 <code>facade.py</code> 暴露</li><li><strong>涉及设备命令执行</strong>：归 <code>device</code>，通过 transport 接口下发</li><li><strong>涉及中转流服务</strong>：归 <code>relay</code></li><li><strong>涉及认证状态</strong>：归 <code>auth</code></li><li><strong>涉及配置读写</strong>：归 <code>config</code></li><li><strong>涉及前端展示</strong>：归 <code>webui</code>，只能依赖 Public API / Internal API</li></ul><p>无法明确归属时，必须先在架构文档中确认边界，再落代码。</p><hr><h2 id="_6-相关文档索引" tabindex="-1">6. 相关文档索引 <a class="header-anchor" href="#_6-相关文档索引" aria-label="Permalink to &quot;6. 相关文档索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>职责</th></tr></thead><tbody><tr><td><code>ARCHITECTURE.md</code></td><td>接口分层与调用关系概述</td></tr><tr><td><code>docs/api/api_v1_spec.md</code></td><td>v1 API 完整契约</td></tr><tr><td><code>docs/spec/player_state_projection_spec.md</code></td><td>播放状态快照语义规范</td></tr><tr><td><code>docs/spec/player_stream_sse_spec.md</code></td><td>SSE 推送协议规范</td></tr><tr><td><code>docs/spec/runtime_specification.md</code></td><td>core 层数据模型与错误体系</td></tr><tr><td><code>docs/spec/playback_coordinator_interface.md</code></td><td>PlaybackCoordinator 接口约束</td></tr><tr><td><code>docs/authentication_architecture.md</code></td><td>认证系统两层状态模型</td></tr><tr><td><code>docs/architecture/runtime_architecture.md</code></td><td>runtime 内部运转与生命周期</td></tr><tr><td><code>docs/architecture/source_architecture.md</code></td><td>source 边界与插件体系</td></tr><tr><td><code>docs/architecture/webui_architecture.md</code></td><td>WebUI 接口依赖边界</td></tr><tr><td><code>docs/development/contributor_guide.md</code></td><td>改动前置规则与文档更新约束</td></tr></tbody></table>`,28)]))}const m=a(n,[["render",c]]);export{h as __pageData,m as default};
